// ── White-label theming ───────────────────────────────────────────────────────
// C is mutated at runtime so a brand change repaints the whole app on re-render.
function _hx2rgb(h){ h=(h||"").replace("#",""); if(h.length===3)h=h.split("").map(c=>c+c).join(""); return [parseInt(h.slice(0,2),16)||0,parseInt(h.slice(2,4),16)||0,parseInt(h.slice(4,6),16)||0]; }
function _rgb2hx(r,g,b){ return "#"+[r,g,b].map(x=>Math.max(0,Math.min(255,Math.round(x))).toString(16).padStart(2,"0")).join(""); }
function _mix(hex,t,a){ const x=_hx2rgb(hex),y=_hx2rgb(t); return _rgb2hx(x[0]+(y[0]-x[0])*a,x[1]+(y[1]-x[1])*a,x[2]+(y[2]-x[2])*a); }
function lighten(h,a){ return _mix(h,"#ffffff",a); }
function darken(h,a){ return _mix(h,"#000000",a); }
function _lum(hex){ const c=_hx2rgb(hex).map(v=>{v/=255; return v<=0.03928?v/12.92:Math.pow((v+0.055)/1.055,2.4);}); return 0.2126*c[0]+0.7152*c[1]+0.0722*c[2]; }
function contrastRatio(a,b){ const l1=_lum(a),l2=_lum(b),hi=Math.max(l1,l2),lo=Math.min(l1,l2); return Math.round(((hi+0.05)/(lo+0.05))*100)/100; }
const _BRAND_DEFAULTS={ navy:C.navy, navyMid:C.navyMid, navyLight:C.navyLight, gold:C.gold, goldLight:C.goldLight, goldDark:C.goldDark, name:"Northbound Logistics" };
const brandStore={
  primary:C.navy, accent:C.gold, logoMode:"mark", mono:"", listeners:new Set(),
  apply({primary,accent,name,logoMode,mono}={}){
    if(primary){ this.primary=primary; C.navy=primary; C.navyMid=lighten(primary,0.14); C.navyLight=lighten(primary,0.90); }
    if(accent){ this.accent=accent; C.gold=accent; C.goldDark=darken(accent,0.18); C.goldLight=lighten(accent,0.82); }
    if(name&&companyStore&&companyStore.set){ companyStore.set({name,legalName:name}); }
    if(logoMode){ this.logoMode=logoMode; }
    if(mono!==undefined){ this.mono=mono; }
    this.fire();
  },
  monogram(){ if(this.mono) return this.mono.toUpperCase().slice(0,3); const n=(companyStore&&companyStore.get?companyStore.get().name:"")||"AH"; return n.split(/\s+/).filter(Boolean).map(w=>w[0]).join("").slice(0,2).toUpperCase()||"AH"; },
  reset(){ this.primary=_BRAND_DEFAULTS.navy; this.accent=_BRAND_DEFAULTS.gold; this.logoMode="mark"; this.mono=""; C.navy=_BRAND_DEFAULTS.navy; C.navyMid=_BRAND_DEFAULTS.navyMid; C.navyLight=_BRAND_DEFAULTS.navyLight; C.gold=_BRAND_DEFAULTS.gold; C.goldLight=_BRAND_DEFAULTS.goldLight; C.goldDark=_BRAND_DEFAULTS.goldDark; this.fire(); },
  fire(){ this.listeners.forEach(l=>l()); },
  subscribe(l){ this.listeners.add(l); return ()=>this.listeners.delete(l); },
};
function useBrand(){ const [,f]=useState(0); useEffect(()=>brandStore.subscribe(()=>f(n=>n+1)),[]); return brandStore; }
