const TERM_DEFAULTS={division:"Division",divisions:"Divisions",employee:"Employee",employees:"Employees",driver:"Driver",drivers:"Drivers"};
const termStore={
  over:{}, listeners:new Set(),
  get(k){ return this.over[k]||TERM_DEFAULTS[k]||k; },
  set(k,v){ const o={...this.over}; if(v&&v.trim())o[k]=v.trim(); else delete o[k]; this.over=o; this.fire(); },
  reset(){ this.over={}; this.fire(); },
  fire(){ this.listeners.forEach(l=>l()); },
  subscribe(l){ this.listeners.add(l); return ()=>this.listeners.delete(l); },
};
function term(k){ return termStore.get(k); }
function useTerms(){ const [,f]=useState(0); useEffect(()=>termStore.subscribe(()=>f(n=>n+1)),[]); return termStore; }
