// Minimal CSV parser (quoted fields, escaped quotes) → {headers, rows}
function parseCSV(text){
  const lines=(text||"").replace(/\r/g,"").split("\n").filter(l=>l.trim().length);
  if(!lines.length) return {headers:[],rows:[]};
  const split=(l)=>{ const out=[]; let cur="",q=false; for(let i=0;i<l.length;i++){ const c=l[i]; if(c==='"'){ if(q&&l[i+1]==='"'){cur+='"';i++;} else q=!q; } else if(c===","&&!q){ out.push(cur); cur=""; } else cur+=c; } out.push(cur); return out.map(s=>s.trim()); };
  const headers=split(lines[0]).map(h=>h.toLowerCase());
  const rows=lines.slice(1).map(l=>{ const cells=split(l); const o={}; headers.forEach((h,i)=>o[h]=cells[i]||""); return o; });
  return {headers,rows};
}

// ── Logo SVG ─────────────────────────────────────────────────────────────────
// Open navy ring + navy diagonal stroke (dot top-right) + gold swoosh (gold dot).
function Logo({ size = 32, light }) {
  if(brandStore.logoMode==="monogram"){
    const ini=brandStore.monogram();
    return <div style={{width:size,height:size,borderRadius:size*0.26,background:light?"#FFFFFF":C.navy,color:light?C.navy:C.gold,display:"inline-flex",alignItems:"center",justifyContent:"center",fontWeight:800,fontSize:size*0.40,letterSpacing:"-0.02em",flexShrink:0}}>{ini}</div>;
  }
  const main = light ? "#FFFFFF" : C.navy;
  const sw = light ? C.goldLight : C.gold;
  return (
    <svg width={size} height={size} viewBox="0 0 120 120" fill="none">
      {/* open ring */}
      <path d="M 38 92 A 46 46 0 1 1 92 78" stroke={main} strokeWidth="11" fill="none" strokeLinecap="round"/>
      {/* navy diagonal stroke */}
      <path d="M 34 86 L 70 44" stroke={main} strokeWidth="11" fill="none" strokeLinecap="round"/>
      <circle cx="70" cy="44" r="8.5" fill={main}/>
      {/* gold swoosh */}
      <path d="M 40 92 C 55 100, 75 96, 86 74" stroke={sw} strokeWidth="11" fill="none" strokeLinecap="round"/>
      <circle cx="86" cy="74" r="8.5" fill={sw}/>
    </svg>
  );
}

