// ── Shared audit store (so moves anywhere log to the Audit Logs page) ─────────
const auditStore = {
  log: [...AUDIT],
  subs: new Set(),
  _id: 100,
  add(entry){
    const now=new Date();
    const time=`Today ${now.toLocaleTimeString([], {hour:"numeric",minute:"2-digit"})}`;
    this.log=[{id:this._id++,time,user:"Natasha Brennan (Admin)",...entry},...this.log];
    this.subs.forEach(fn=>fn());
  },
  subscribe(fn){ this.subs.add(fn); return ()=>this.subs.delete(fn); },
};
function useAudit(){
  const [,force]=useState(0);
  useEffect(()=>auditStore.subscribe(()=>force(n=>n+1)),[]);
  return auditStore;
}

// ── Users store (Admin → Users & Roles). Mutations log to the audit trail. ──────
const USER_ROLES=["Admin","Recruiter","Hiring Manager","Interviewer","Payroll Admin","Safety Manager","Employee"];
const USER_DEPTS=["HR","Engineering","Product","Operations","Safety & Compliance","Payroll","Finance","Dispatch"];
const ASSIGNABLE_HUBS=["ATS / Recruiting","Admin","HRIS","Safety","Payroll","Maintenance","Fleet & Dispatch","Rewards & Store","E-Signature","Executive"];
function defaultHubs(role){
  if(role==="Admin") return [...ASSIGNABLE_HUBS];
  if(role==="Payroll Admin") return ["Payroll","HRIS"];
  if(role==="Safety Manager") return ["Safety","Fleet & Dispatch"];
  if(role==="Employee") return ["Rewards & Store"];
  return ["ATS / Recruiting"]; // Recruiter, Hiring Manager, Interviewer
}
const userStore={
  users:USERS.map(u=>({lastActive:u.status==="Active"?"Today":u.status==="Inactive"?"—":"Pending",hubs:u.hubs||defaultHubs(u.role),...u})),
  listeners:new Set(), _id:100,
  all(){ return this.users; },
  invite({name,email,role,dept,hubs}){ this.users=[...this.users,{id:this._id++,name,email,role,dept,hubs:hubs||defaultHubs(role),status:"Pending",joined:"Today",lastActive:"Invite sent"}]; auditStore.add({action:"Invited user",target:name+" ("+role+")",type:"create"}); this.fire(); },
  update(id,patch){ const u=this.users.find(x=>x.id===id); this.users=this.users.map(x=>x.id===id?{...x,...patch}:x); if(u){ if(patch.hubs&&JSON.stringify(patch.hubs)!==JSON.stringify(u.hubs)) auditStore.add({action:"Updated hub access",target:u.name,type:"update"}); else if(patch.role&&patch.role!==u.role) auditStore.add({action:"Changed role to "+patch.role,target:u.name,type:"update"}); else auditStore.add({action:"Edited user",target:u.name,type:"update"}); } this.fire(); },
  setStatus(id,status){ const u=this.users.find(x=>x.id===id); this.users=this.users.map(x=>x.id===id?{...x,status,lastActive:status==="Active"?"Today":x.lastActive}:x); if(u) auditStore.add({action:status==="Inactive"?"Deactivated user":"Reactivated user",target:u.name,type:status==="Inactive"?"delete":"update"}); this.fire(); },
  resend(id){ const u=this.users.find(x=>x.id===id); if(u){ auditStore.add({action:"Resent invite",target:u.name,type:"update"}); } this.fire(); },
  fire(){ this.listeners.forEach(l=>l()); },
  subscribe(l){ this.listeners.add(l); return ()=>this.listeners.delete(l); },
};
function useUsers(){ const [,f]=useState(0); useEffect(()=>userStore.subscribe(()=>f(n=>n+1)),[]); return userStore; }

