function sevDot(s) {
  return {Positive:"#16A34A",Minor:"#D97706",Moderate:"#EA580C",Major:"#2563EB",Critical:"#DC2626",Info:"#9CA3AF",Neutral:"#9CA3AF"}[s]||"#9CA3AF";
}

function getDivTotals() {
  const m={};
  SPSS_EVENTS.forEach(e=>{
    if(!m[e.division]) m[e.division]={division:e.division,pts:0,events:0,overdue:0,preventable:0};
    m[e.division].pts+=e.pts; m[e.division].events+=1;
    if(e.actionStatus==="OVERDUE") m[e.division].overdue+=1;
    if(e.eventDetail.toLowerCase().includes("preventable accident")&&!e.eventDetail.toLowerCase().includes("non-")) m[e.division].preventable+=1;
  });
  return Object.values(m).sort((a,b)=>a.pts-b.pts);
}

