// Role → file category
function roleCategory(role=""){
  const r=role.toLowerCase();
  if(r.includes("owner")||r.includes("lease")) return "owner_op";
  if(r.includes("mechanic")||r.includes("technician")) return "mechanic";
  if(r.includes("driver")||r.includes("class 1")||r.includes("operator")) return "driver";
  return "office";
}
