function spssBand(s){
  if(s>=80) return {label:"Good standing",color:C.green,bg:C.greenBg};
  if(s>=60) return {label:"Satisfactory",color:C.amber,bg:C.amberBg};
  if(s>=40) return {label:"Coaching / review",color:"#EA580C",bg:"#FFF1E8"};
  return {label:"Termination review",color:C.red,bg:C.redBg};
}
// Build a fully-documented file for an established employee (docs Valid unless overridden)
function buildFile(id,name,role,division,hireDate,opts={}){
  const cat=roleCategory(role);
  const ov=opts.docs||{};
  const docs=SAFETY_REQ[cat].map(d=>{
    if(d.live) return {...d,status:"Active"};
    const o=ov[d.key]||{};
    return {...d,status:o.status||"Valid",expiry:o.expiry||(d.expires?(opts.defExpiry||"2027-03-15"):null)};
  });
  return {id,name,avatar:name[0],role,category:cat,division,hireDate,location:opts.location||"Calgary, AB",docs,
    spss:cat==="driver"||cat==="owner_op"?{score:opts.spss??92}:null,
    events:opts.events||[], training:opts.training||[], isNew:!!opts.isNew};
}
// File compliance roll-up
function fileStatus(file){
  const docs=file.docs||[];
  const scored=docs.filter(d=>!d.live);
  const valid=scored.filter(d=>d.status==="Valid").length;
  const completeness=scored.length?Math.round((valid/scored.length)*100):100;
  const missing=scored.filter(d=>d.status==="Missing").length;
  const expired=scored.filter(d=>d.status==="Expired").length;
  const expiring=scored.filter(d=>d.status==="Expiring").length;
  const pending=scored.filter(d=>d.status==="Pending").length;
  const critBroken=scored.some(d=>d.critical&&(d.status==="Missing"||d.status==="Expired"));
  let status,color,bg;
  if(file.isNew&&pending>0&&valid<=2){status="Pending setup";color=C.blue;bg=C.blueBg;}
  else if(critBroken||expired){status="Non-compliant";color=C.red;bg=C.redBg;}
  else if(missing||expiring||pending){status="Action needed";color=C.amber;bg=C.amberBg;}
  else {status="Compliant";color=C.green;bg=C.greenBg;}
  return {completeness,missing,expired,expiring,pending,status,color,bg};
}

// Flatten every expiry-bearing document across all files into a renewals list
function gatherRenewals(files){
  const NOW=new Date("2026-06-24");
  const out=[];
  files.forEach(f=>{
    (f.docs||[]).filter(d=>d.expiry&&!d.live).forEach(d=>{
      const exp=new Date(d.expiry);
      const days=Math.round((exp-NOW)/86400000);
      out.push({emp:f.name,fileId:f.id,role:f.role,division:f.division,doc:d.label,critical:d.critical,status:d.status,expiry:d.expiry,days});
    });
  });
  return out.sort((a,b)=>a.days-b.days);
}

