const safetyStore={
  extra:[],
  listeners:new Set(),
  all(){ return [...this.extra,..._seedFiles]; },
  subscribe(l){ this.listeners.add(l); return ()=>this.listeners.delete(l); },
  createFromHire(cand){
    const cat=roleCategory(cand.role);
    const docs=SAFETY_REQ[cat].map(d=>{
      if(d.live) return {...d,status:"Active"};
      // a freshly hired record: a couple of items auto-carry from the ATS, the rest pending/missing
      if(d.key==="app"||d.key==="crc"||d.key==="drug") return {...d,status:"Valid",expiry:null};
      if(d.critical) return {...d,status:"Missing",expiry:null};
      return {...d,status:"Pending",expiry:null};
    });
    const file={id:8000+Math.floor(Math.random()*1000),name:cand.name,avatar:(cand.name[0]||"?").toUpperCase(),
      role:cand.role,category:cat,division:cand.division||"Fleet Operations",hireDate:"Today",
      location:cand.location||"Calgary, AB",docs,
      spss:(cat==="driver"||cat==="owner_op")?{score:100}:null, events:[], training:[], isNew:true};
    file.docs=docs;
    this.extra=[file,...this.extra];
    this.listeners.forEach(l=>l());
    return file;
  },
};
