// Date helpers for the auto-renew scheduler
function quickDate(off){
  const d=new Date();
  if(off==="fom"){ d.setMonth(d.getMonth()+1,1); }
  else if(typeof off==="number"&&off<=7){
    // "next <weekday>" — off is a target weekday (1=Mon..) ; jump to next occurrence
    const target=off%7;
    let add=(target-d.getDay()+7)%7; if(add===0) add=7;
    d.setDate(d.getDate()+add);
  } else { d.setDate(d.getDate()+Number(off)); }
  return d.toISOString().slice(0,10);
}
function fmtDate(iso){
  if(!iso) return "";
  const d=new Date(iso+"T00:00:00");
  return d.toLocaleDateString(undefined,{weekday:"short",month:"short",day:"numeric",year:"numeric"});
}

