const EFF_ROLES={
  mechanic:{label:"Mechanic efficiency",desc:"Billable wrench time vs. available shop hours",color:C.blue},
  recruiter:{label:"Recruiter efficiency",desc:"Hires per recruiter vs. time-to-fill target",color:C.purple},
  dispatcher:{label:"Dispatcher efficiency",desc:"On-time loads dispatched per dispatcher",color:C.green},
};
function EfficiencyTile({role,companies}){
  const meta=EFF_ROLES[role];
  const src=companies&&companies.length?companies:EFF_COMPANIES;
  const rows=[...src].sort((a,b)=>b[role]-a[role]);
  const avg=Math.round(src.reduce((s,c)=>s+c[role],0)/src.length);
  const best=rows[0]||{co:"—",[role]:0}, worst=rows[rows.length-1]||{co:"—",[role]:0};
  return(
    <Card style={{padding:0,overflow:"hidden"}}>
      <div style={{padding:"14px 16px",borderBottom:`1px solid ${C.border}`,display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
        <div>
          <div style={{fontSize:13.5,fontWeight:800,color:C.text}}>{meta.label}</div>
          <div style={{fontSize:11,color:C.textMuted,marginTop:2}}>{meta.desc}</div>
        </div>
        <ExportMenu sm title={meta.label+" by company"} headers={["Company",meta.label,"vs group avg"]} rows={rows.map(c=>[c.co,c[role]+"%",(c[role]-avg>=0?"+":"")+(c[role]-avg)+"%"])}/>
      </div>
      <div style={{padding:"12px 16px"}}>
        <div style={{display:"flex",alignItems:"baseline",gap:8,marginBottom:12}}>
          <span style={{fontSize:30,fontWeight:800,color:meta.color}} className="tnum">{avg}%</span>
          <span style={{fontSize:11.5,color:C.textMuted}}>group average</span>
        </div>
        {rows.map(c=>(
          <div key={c.co} style={{marginBottom:9}}>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:11.5,marginBottom:3}}><span style={{color:C.textMid,fontWeight:600}}>{c.co}</span><span style={{color:C.text,fontWeight:700}}>{c[role]}%</span></div>
            <div style={{height:7,background:C.bg,borderRadius:5,overflow:"hidden"}}><div style={{height:"100%",width:c[role]+"%",background:c[role]>=avg?meta.color:C.amber,borderRadius:5}}/></div>
          </div>
        ))}
        <div style={{fontSize:11,color:C.textMuted,marginTop:8,lineHeight:1.5}}>Top: <b style={{color:C.green}}>{best.co}</b> ({best[role]}%) · Needs attention: <b style={{color:C.amber}}>{worst.co}</b> ({worst[role]}%)</div>
      </div>
    </Card>
  );
}
