          <div style={{height:7,background:C.bg,borderRadius:5,overflow:"hidden"}}><div style={{height:"100%",width:r.retention+"%",background:r.retention>=88?C.green:r.retention>=80?C.amber:C.red,borderRadius:5}}/></div>
