const _SITE_PRESETS=[
  {name:"Grande Prairie Satellite Yard",type:"Satellite yard",lat:55.1700,lng:-118.7900,radiusM:200},
  {name:"Kamloops Satellite Yard",type:"Satellite yard",lat:50.6740,lng:-120.3270,radiusM:200},
  {name:"Saskatoon Drop Yard",type:"Drop yard",lat:52.1330,lng:-106.6700,radiusM:150},
];
