const DIV_SITE={"Northline Carriers":"Calgary Terminal","Operations":"Calgary Terminal","Prairie Haul":"Calgary Terminal","Cascade Logistics":"Edmonton Terminal","Summit Freight":"Surrey Depot"};
function siteForDivision(div){ return worksiteStore.all().find(w=>w.name===DIV_SITE[div])||worksiteStore.all()[0]; }
function haversineM(a,b,c,d){ const R=6371000,toR=x=>x*Math.PI/180; const dLat=toR(c-a),dLng=toR(d-b); const s=Math.sin(dLat/2)**2+Math.cos(toR(a))*Math.cos(toR(c))*Math.sin(dLng/2)**2; return Math.round(R*2*Math.atan2(Math.sqrt(s),Math.sqrt(1-s))); }
function nearestSite(lat,lng){ let best=Infinity,near=null; worksiteStore.all().forEach(s=>{const d=haversineM(s.lat,s.lng,lat,lng); if(d<best){best=d;near=s;}}); return {site:near,distanceM:best}; }
function isMobileWorker(person){ if(!person) return false; const c=operatorClass(person.role,person.category); return c.contractor||person.category==="driver"; }
// Verify a punch against EVERY registered yard — nearest match wins, so a punch at
// a satellite yard is on-site there. Mobile workers (drivers) are recorded, not flagged.
function verifyAt(person,lat,lng){ const {site,distanceM}=nearestSite(lat,lng); const inside=!!site&&distanceM<=site.radiusM; const mobile=isMobileWorker(person); return {site:site?site.name:"—",type:site?site.type:"",distanceM,inside,mobile,flagged:!inside&&!mobile,lat:Math.round(lat*10000)/10000,lng:Math.round(lng*10000)/10000}; }
function computeGeo(site,onSite){ const j=onSite?(Math.random()*0.0012-0.0006):(0.030+Math.random()*0.015); return {lat:site.lat+j,lng:site.lng+(onSite?j*0.7:-j)}; }
// Global hours-of-service rule sets. The engine picks the right one per driver by region.
const HOS_RULES={
  us:     {key:"us",     name:"US FMCSA — 70 h / 8 days",                  region:"United States",            cycle:70, cycleDays:8, dailyDrive:11, dutyWindow:14, reset:"34 h",       warnWatch:14, warnCritical:8},
  caSouth:{key:"caSouth",name:"Canada NSC — 70 h / 7 days (South of 60°)", region:"Canada · South of 60°",     cycle:70, cycleDays:7, dailyDrive:13, dutyWindow:16, reset:"36 h",       warnWatch:13, warnCritical:8},
  caNorth:{key:"caNorth",name:"Canada NSC — 80 h / 7 days (North of 60°)", region:"Canada · North of 60°",     cycle:80, cycleDays:7, dailyDrive:15, dutyWindow:18, reset:"36 h",       warnWatch:15, warnCritical:9},
  eu:     {key:"eu",     name:"EU 561/2006 — 56 h / week",                 region:"European Union",           cycle:56, cycleDays:7, dailyDrive:9,  dutyWindow:13, reset:"45 h weekly",warnWatch:9,  warnCritical:5},
};
const _CA_NORTH=["YT","NT","NU"];
const _CA_SOUTH=["AB","BC","SK","MB","ON","QC","NB","NS","PE","NL"];
function hosRuleFor(person){
  const loc=((person&&person.location)||"").toUpperCase();
  const m=loc.match(/,\s*([A-Z]{2})\b/)||loc.match(/\b([A-Z]{2})\b/);
  const code=m?m[1]:null;
  if(code&&_CA_NORTH.includes(code)) return HOS_RULES.caNorth;
  if(code&&_CA_SOUTH.includes(code)) return HOS_RULES.caSouth;
  if(/EUROPE|EU|GERMANY|FRANCE|POLAND|SPAIN|ITALY|NETHERLAND/.test(loc)) return HOS_RULES.eu;
  if(code) return HOS_RULES.us; // any other 2-letter region code → US state
  const country=(companyStore.get&&companyStore.get().profile&&companyStore.get().profile.country)||"Canada";
  return /UNITED STATES|USA|US/.test(String(country).toUpperCase())?HOS_RULES.us:HOS_RULES.caSouth;
}
// Company drivers don't punch — their duty status & location come from the ELD.
function eldFor(person){
  const unit=FLEET_UNITS.find(u=>u.driver===person.name);
  const provider=unit?unit.tele:"Samsara";
  const id=person.id;
  const rule=hosRuleFor(person);
  const duty=["Driving","On Duty (not driving)","Driving","Off Duty"][id%4];
  const onDuty=4+(id%6);
  const driving=Math.min(onDuty,3+(id%5));
  const cycle=rule.cycle;
  const cycleUsed=Math.min(cycle, Math.round(cycle*0.55)+(id%Math.max(1,Math.round(cycle*0.38))));
  const cycleLeft=Math.max(0,cycle-cycleUsed);
  return {provider,duty,onDuty,driving,cycle,cycleUsed,cycleLeft,rule,unit:unit?unit.id:null,loc:person.location||"en route",onClock:duty==="Driving"||duty==="On Duty (not driving)"};
}
const PROVIDER_CONN={Samsara:"samsara",Geotab:"geotab",Motive:"motive",ISAAC:"isaac",Lytx:"lytx",Netradyne:"netradyne"};
// Hours-of-service status from the ELD — only meaningful when the provider is connected.
function hosStatus(person){
  if(!person||person.category!=="driver") return null;
  const eld=eldFor(person);
  const connId=PROVIDER_CONN[eld.provider];
  const c=connId?connectorStore.all().find(x=>x.id===connId):null;
  const connected=connId?(c&&c.status==="Connected"):true;
  if(!connected) return {connected:false,provider:eld.provider};
  const rule=eld.rule;
  const level=eld.cycleLeft<=rule.warnCritical?"critical":eld.cycleLeft<=rule.warnWatch?"watch":"ok";
  return {connected:true,provider:eld.provider,cycleLeft:eld.cycleLeft,driving:eld.driving,onDuty:eld.onDuty,duty:eld.duty,unit:eld.unit,level,rule};
}
