  const [simOff,setSimOff]=useState(false);
  const [now,setNow]=useState(Date.now());
  useEffect(()=>{const t=setInterval(()=>setNow(Date.now()),1000);return ()=>clearInterval(t);},[]);
  const status=clock.statusOf(emp);
  const hrs=clock.hoursToday(emp);
  const myPunches=clock.all().filter(p=>p.emp===emp).sort((a,b)=>b.ts-a.ts);
  const onNow=clock.onClock();
  const wsites=useWorksites();
  const geofenceOn=feat.geofence&&feat.timeClock;
