  const mobile=isMobileWorker(person);
  const policy=clock.policyFor(person);
  const conn=useConnectors();
  const isDriver=person&&person.category==="driver";
  const eld=isDriver?eldFor(person):null;
  const eldConnId=eld?PROVIDER_CONN[eld.provider]:null;
