// ── PAYROLL HUB ──────────────────────────────────────────────────────────────
// Pays people off the SAME record: mileage for company drivers, settlements for
// owner-operators, salary/hourly for staff — deductions, benefits & remittances.
function parseRate(s){ const m=String(s).match(/\$([0-9.]+)/); return m?parseFloat(m[1]):0; }
function payFor(p){
  const h=deriveHR(p), cls=h.cls;
  if(cls.contractor){
    const revenue=14000+(p.id%9)*1180;
    const fuel=Math.round(revenue*0.28);
    const insurance=Math.round(revenue*0.04);
    const admin=Math.round(revenue*0.02);
    const ded=fuel+insurance+admin;
    return {kind:"Settlement",miles:Math.round(revenue/2.15),revenue,fuel,insurance,admin,ded,net:revenue-ded,basis:"88% line-haul"};
  }
  let gross=0,basis="";
  if(p.category==="driver"){ const rate=parseRate(h.payRate); const miles=4200+(p.id%50)*92; gross=Math.round(rate*miles); basis=`${miles.toLocaleString()} mi @ $${rate.toFixed(2)}`; }
  else if(p.category==="mechanic"){ const rate=parseRate(h.payRate); const hours=80+(p.id%10); gross=Math.round(rate*hours); basis=`${hours} hrs @ $${rate.toFixed(2)}/hr`; if(companyStore.hasFeature("timeClock")){ const ot=Math.max(0,Math.round(clockStore.hoursToday(p.name)-8)); if(ot>0){ gross+=Math.round(rate*1.5*ot); basis+=` + ${ot}h OT ⏱`; } } }
  else { const annual=parseRate(h.payRate)*1000; gross=Math.round(annual/24); basis="Salary · semi-monthly"; }
  const cpp=Math.round(gross*0.0595), ei=Math.round(gross*0.0166), tax=Math.round(gross*0.18);
  const b=benefitsFor(p);
  const ben=b.eligible?(b.tier==="Family"?92:48):0;
  const rrsp=b.rrsp.includes("match")?Math.round(gross*0.04):0;
  const ded=cpp+ei+tax+ben+rrsp;
  return {kind:"Payroll",gross,basis,cpp,ei,tax,ben,rrsp,ded,net:gross-ded};
}
// Ellie payroll audit — catches likely errors before a run is processed
const PAYROLL_RUN_FLAGS=[
  {emp:"Tariq Driver-D",title:"Mileage spike vs history",detail:"Entered 11,240 mi — about 2.4× Tariq's 6-month average (~4,700 mi). Looks like a duplicate trip import; would overpay roughly $3,900.",fix:"Verify the trip sheet before processing",save:3900},
  {emp:"Liam Driver-E",title:"No miles entered",detail:"Liam has 0 mi recorded and would be paid $0 this run. Either mileage is missing or he was on leave.",fix:"Enter miles or move to off-cycle",save:0},
];
const PAYROLL_CHECKS=["Mileage vs history","Hours vs schedule","Rate vs approved comp","New-hire banking","Leave overlap","Duplicate entries","Net pay > 0","CPP/EI YTD caps","Benefit deductions","Classification (T4 vs T4A)","Stat-holiday pay","Off-cycle reconciliation"];
function detectPayrollIssues(employees,hr){
  const issues=[];
  const inPeriod=d=>d>="2026-06-16"&&d<="2026-06-30";
  PAYROLL_RUN_FLAGS.forEach(f=>{ if(employees.some(e=>e.name===f.emp)) issues.push({sev:f.save===0?"error":"error",...f}); });
  (hr.compChanges||[]).filter(c=>!c.rejected&&c.step<3&&inPeriod(c.effective)).forEach(c=>{
    issues.push({sev:"error",emp:c.emp,title:"Rate change effective but not approved",detail:`${c.type} (${c.oldRate} → ${c.newRate}) is effective ${c.effective} but still pending ${COMP_CHAIN[c.step]} approval — ${c.emp} will be paid the OLD rate. That's an underpayment.`,fix:"Approve in HR → Compensation before processing"});
  });
  employees.filter(e=>e.isNew).forEach(e=>issues.push({sev:"warning",emp:e.name,title:"First pay — banking unconfirmed",detail:`${e.name} is a new hire on their first run; direct-deposit details aren't verified yet.`,fix:"Confirm banking before processing"}));
  (hr.requests||[]).filter(r=>r.status!=="Denied"&&inPeriod(r.from)).forEach(r=>issues.push({sev:"warning",emp:r.emp,title:"Leave overlaps a paid period",detail:`${r.emp} has ${r.days}d ${r.type} leave overlapping this period but is set to full pay. Verify the PTO offset so they're not paid twice.`,fix:"Confirm hours / PTO offset"}));
  const order={error:0,warning:1,info:2};
  return issues.sort((a,b)=>order[a.sev]-order[b.sev]);
}

